example.code:
{
  "sop_id": "sop-ga4-setup",
  "service_name": "Analytics setup",
  "version": "1.0.0",
  "owner": "U_FOUNDER",
  "steps": [
    {
      "n": 1,
      "name": "intake",
      "inputs": [
        "client brief"
      ],
      "action": "read brief, confirm scope",
      "decisions": [],
      "quality_gates": [
        "scope confirmed in writing"
      ],
      "escalation": "U_FOUNDER if scope unclear",
      "time_budget_min": 30
    },
    {
      "n": 2,
      "name": "ga4-property",
      "inputs": [
        "GA admin access"
      ],
      "action": "create GA4 property",
      "decisions": [],
      "quality_gates": [
        "property visible to client"
      ],
      "escalation": "U_FOUNDER if access denied",
      "time_budget_min": 20
    },
    {
      "n": 3,
      "name": "gtm-install",
      "inputs": [
        "CMS admin"
      ],
      "action": "install GTM via template",
      "decisions": [
        {
          "condition": "CMP present",
          "branch_a": "consent template",
          "branch_b": "default-deny + sales flag"
        }
      ],
      "quality_gates": [
        "GTM preview shows page_view"
      ],
      "escalation": "U_FOUNDER if 4xx",
      "time_budget_min": 60
    },
    {
      "n": 4,
      "name": "events",
      "inputs": [
        "event list from intake"
      ],
      "action": "configure conversion events",
      "decisions": [],
      "quality_gates": [
        "DebugView fires each event"
      ],
      "escalation": "U_FOUNDER if events stuck",
      "time_budget_min": 45
    },
    {
      "n": 5,
      "name": "handoff",
      "inputs": [
        "dashboard access list"
      ],
      "action": "share access + write handoff doc",
      "decisions": [],
      "quality_gates": [
        "client signs acceptance"
      ],
      "escalation": "U_FOUNDER if client unresponsive 48h",
      "time_budget_min": 30
    }
  ],
  "engagement_acceptance": [
    "client signs handoff",
    "all events fire in DebugView",
    "GTM preview clean"
  ]
}
